parameters.jsCode:
const webhook = $('Webhook').first().json;
const sheetItems = $('Fetch Contacts from Sheet').all();
const sheet = (sheetItems.length > 0 && sheetItems[0].json) ? sheetItems[0].json : {};

const schoolId = webhook.schoolId || '';
const assessmentName = webhook.assessmentName || 'Sodhana 1';

const encodedAssessment = encodeURIComponent(assessmentName);
const pdfUrl = `https://viswam-report-card.vercel.app/api/reports/school/${schoolId}/pdf?assessmentName=${encodedAssessment}`;
const jsonPdfUrl = `${pdfUrl}&json=true`;

return [{
  json: {
    schoolId,
    assessmentName,
    pdfUrl,
    jsonPdfUrl,
    schoolName: webhook.schoolName || sheet['School Name'] || sheet['NSF School name'] || 'Unknown School',
    principalEmail: sheet['School Email Id'] || sheet['Principal Email'] || webhook.principalEmail || '',
    whatsappNo: webhook.whatsappNo || sheet['POC Contact No.'] || sheet['Whatsapp No'] || '',
    studentCount: webhook.studentCount || 0
  }
}];

